sql:
SELECT COUNT(*) 
FROM flight_updates 
WHERE user_id = (SELECT user_id FROM users WHERE username = 'admin');

external_knowledge:
- 'journeys' refers to bookings;
- 'frequency of their voyages' refers to the total number of bookings per passenger;
- 'total expenditure' is the sum of all payments made by the passenger;
- 'average expenditure per journey' is calculated by dividing the total payments by the number of bookings;
- 'most generous with their wallets' refers to passengers with the highest average spend per booking.

